import React from 'react';
import { BookOpen, MapPin, Coffee, Moon, Film, Map } from 'lucide-react';

function LogbookView() {
  const logbookEntries = [
    { id: 1, time: 'Idag, 14:30', title: 'Lunch vid sjön', type: 'stopp', icon: <MapPin size={18} color="#D35400" />, desc: 'Solen sken, vi käkade mackor och njöt av utsikten.' },
    { id: 2, time: 'Idag, 10:15', title: 'Tankning & Kaffe', type: 'service', icon: <Coffee size={18} color="#2D5A27" />, desc: 'Snabbstopp innan bergen.' },
    { id: 3, time: 'Igår, 19:00', title: 'Nattplats: Skogsbrynet', type: 'natt', icon: <Moon size={18} color="#34495E" />, desc: 'Helt tyst, bara vi och ugglorna.' }
  ];

  return (
    <div style={{ padding: '20px' }} className="animate-fade-in">
      <header style={{ marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '10px' }}>
        <BookOpen size={28} color="#2D5A27" />
        <div>
          <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0 }}>Loggbok</h1>
          <p style={{ color: '#636E72', margin: '5px 0 0 0', fontSize: '12px' }}>Sommaren 2026 • 840 km totalt</p>
        </div>
      </header>

      {/* Premium-knapp för export */}
      <button style={exportBtnStyle}>
        <Film size={20} />
        Exportera som TravelMap-film
      </button>

      {/* Tidslinjen med snygga ikoner */}
      <div style={{ borderLeft: '2px solid #DCEBDE', marginLeft: '20px', paddingLeft: '20px', marginTop: '10px' }}>
        {logbookEntries.map((entry) => (
          <div key={entry.id} style={{ marginBottom: '25px', position: 'relative' }}>
            {/* Ikonen på tidslinjen */}
            <div style={{ position: 'absolute', left: '-38px', top: '0', backgroundColor: '#FFF', width: '32px', height: '32px', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', border: '2px solid #DCEBDE', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
              {entry.icon}
            </div>

            <span style={{ fontSize: '12px', color: '#95A5A6', fontWeight: 'bold' }}>{entry.time}</span>
            <div style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', marginTop: '5px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
              <h3 style={{ margin: '0 0 5px 0', fontSize: '16px', color: '#2D3436' }}>{entry.title}</h3>
              <p style={{ margin: 0, fontSize: '14px', color: '#636E72', lineHeight: '1.4' }}>{entry.desc}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Tom statisk karta i botten av loggboken */}
       <div style={{ backgroundColor: '#DCEBDE', height: '120px', borderRadius: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', marginTop: '30px', boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.05)' }}>
        <div style={{ textAlign: 'center', color: '#2D5A27', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <Map size={24} style={{ marginBottom: '5px', opacity: 0.8 }} />
          <span style={{ fontWeight: 'bold', fontSize: '12px' }}>Resrutt</span>
        </div>
      </div>

    </div>
  );
}

const exportBtnStyle = { 
  backgroundColor: '#D35400', 
  color: 'white', 
  border: 'none', 
  padding: '16px', 
  borderRadius: '15px', 
  fontSize: '16px', 
  fontWeight: 'bold', 
  cursor: 'pointer', 
  width: '100%', 
  marginBottom: '30px', 
  display: 'flex', 
  justifyContent: 'center', 
  alignItems: 'center', 
  gap: '10px',
  boxShadow: '0 4px 10px rgba(211, 84, 0, 0.2)'
};

export default LogbookView;
